@nbstrike thanks I'll look at this.

From @nbstrike in #7134.

"The next problem I ran into was the uvm WRONG_TYPE/NO_SEQUENCE issue, this seems to be an issue with $cast -- specifically when a class type parameter with a default is used as the default of another type parameter (nested/defaulted class type path), and one side is implicit-default while the other is explicit-equivalent. For example:

```
package p;
  class W #(type T = int);
    T v;
  endclass

  class Holder #(type U = W#());
    U u;
  endclass

  typedef Holder#()         H_imp_t;       // implicit default
  typedef Holder#(W#(int))  H_exp_t;       // explicit equivalent default
endpackage

module t;
  p::H_imp_t imp;
  p::H_exp_t exp;

  initial begin
    imp = new;
    if (!$cast(exp, imp)) begin
      $display("WRONG_TYPE");
      $fatal;
    end
    $display("PASS");
    $finish;
  end
endmodule
```

This hack worked for me, and hopefully points in the right direction but come from ai and probably leaves something to be desired:

```
diff --git a/src/V3Param.cpp b/src/V3Param.cpp
index aeddbbeb4..93881adb7 100644
--- a/src/V3Param.cpp
+++ b/src/V3Param.cpp
@@ -972,6 +972,25 @@ class ParamProcessor final {
         }
     }

+    static AstParamTypeDType* findGParamTypeByName(AstNodeModule* modp, const string& name) {
+        for (AstNode* stmtp = modp->stmtsp(); stmtp; stmtp = stmtp->nextp()) {
+            AstParamTypeDType* const ptp = VN_CAST(stmtp, ParamTypeDType);
+            if (!ptp || !ptp->isGParam()) continue;
+            if (ptp->name() == name) return ptp;
+        }
+        return nullptr;
+    }
+
+    bool matchesResolvedDefaultType(const AstNodeDType* exprp, AstNodeModule* srcModp,
+                                    AstParamTypeDType* modvarp) const {
+        AstNodeModule* const defaultModp = VN_CAST(srcModp->user4p(), NodeModule);
+        if (!defaultModp) return false;
+        AstParamTypeDType* const defaultParamTypep = findGParamTypeByName(defaultModp, modvarp->name());
+        if (!defaultParamTypep) return false;
+        const AstNodeDType* const defaultTypep = defaultParamTypep->skipRefToNonRefp();
+        return defaultTypep && exprp->similarDType(defaultTypep);
+    }
+
     void cellPinCleanup(AstNode* nodep, AstPin* pinp, AstNodeModule* srcModp, string& longnamer,
                         bool& any_overridesr) {
         if (!pinp->exprp()) return;  // No-connect
@@ -1057,7 +1076,8 @@ class ParamProcessor final {
                                   << " violates parameter's forwarding type '"
                                   << modvarp->fwdType().ascii() << "'");
                 }
-                if (exprp->similarDType(origp)) {
+                if (exprp->similarDType(origp)
+                    || matchesResolvedDefaultType(exprp, srcModp, modvarp)) {
                     // Setting parameter to its default value.  Just ignore it.
                     // This prevents making additional modules, and makes coverage more
                     // obvious as it won't show up under a unique module page name.
